import React, { useState, useEffect } from "react";
import axios from "axios";
import "./Admin.css";

const Admin = () => {
  const [currentSection, setCurrentSection] = useState("dashboard");
  const [data, setData] = useState([]);
  const [formData, setFormData] = useState({});
  const [isEditing, setIsEditing] = useState(false);
  const [roles, setRoles] = useState(["Administrator", "Manager"]);

  useEffect(() => {
    if (currentSection !== "dashboard") fetchData(currentSection);
  }, [currentSection]);

  const fetchData = async (section) => {
    try {
      const response = await axios.get(`/api/${section}`);
      setData(response.data);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  const handleSave = async () => {
    try {
      if (isEditing) {
        await axios.put(`/api/${currentSection}/${formData.id}`, formData);
      } else {
        await axios.post(`/api/${currentSection}`, formData);
      }
      fetchData(currentSection);
      setFormData({});
      setIsEditing(false);
    } catch (error) {
      console.error("Error saving data:", error);
    }
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/${currentSection}/${id}`);
      fetchData(currentSection);
    } catch (error) {
      console.error("Error deleting data:", error);
    }
  };

  const renderTable = () => {
    if (!data.length) return <p>No data available.</p>;

    return (
      <table className="admin-table">
        <thead>
          <tr>
            {Object.keys(data[0]).map((key) => (
              <th key={key}>{key}</th>
            ))}
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {data.map((item) => (
            <tr key={item.id}>
              {Object.values(item).map((value, index) => (
                <td key={index}>{value}</td>
              ))}
              <td>
                <button
                  className="btn-edit"
                  onClick={() => {
                    setFormData(item);
                    setIsEditing(true);
                  }}
                >
                  Edit
                </button>
                <button
                  className="btn-delete"
                  onClick={() => handleDelete(item.id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderForm = () => {
    return (
      <div className="form-container">
        {Object.keys(formData).map((key) => (
          <div className="form-group" key={key}>
            <label>{key}</label>
            <input
              type="text"
              value={formData[key] || ""}
              onChange={(e) =>
                setFormData({ ...formData, [key]: e.target.value })
              }
            />
          </div>
        ))}
        <button className="btn-save" onClick={handleSave}>
          {isEditing ? "Update" : "Save"}
        </button>
      </div>
    );
  };

  return (
    <div className="admin-panel">
      <aside className="sidebar">
        <h2>Admin Panel</h2>
        <nav>
          <button onClick={() => setCurrentSection("dashboard")}>Dashboard</button>
          <button onClick={() => setCurrentSection("clients")}>Clients</button>
          <button onClick={() => setCurrentSection("countries")}>Countries</button>
          <button onClick={() => setCurrentSection("tours")}>Tours</button>
          <button onClick={() => setCurrentSection("bookings")}>Bookings</button>
        </nav>
      </aside>

      <main className="main-content">
        {currentSection === "dashboard" ? (
          <div className="dashboard">
            <h3>Welcome to the Admin Dashboard</h3>
            <p>Use the navigation menu to manage data.</p>
          </div>
        ) : (
          <div>
            <h3>{currentSection}</h3>
            {renderTable()}
            {renderForm()}
          </div>
        )}
      </main>
    </div>
  );
};

export default Admin;
